+        "from_stdin requires async/eventable stdin; regular-file stdin is "
+        "unsupported")
+        .emit(dh);
+      co_await queue->enqueue(std::nullopt);
+      co_return;
+    }
     // Set stdin to non-blocking for event-driven IO.
